import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  // ✅ state
  const [index, setIndex] = useState(0);

  // ✅ تغيير النص كل 2 ثواني
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  // ✅ بيانات البطاقات
  const cardsData = [
    {
      id: 1,
      icon: "🔲",
      title: "رمز QR",
      badge: "📱 الخطوة الأولى",
      description: "طريقة ذكية لبدء الطلب بدون انتظار النادل. الزبون يمسح الرمز الموجود على الطاولة ليبدأ رحلة الطعام الرقمية.",
      features: [
        "مسح سريع خلال ثانية واحدة",
        "قائمة طعام تفاعلية بالصور والأسعار",
        "إضافة أطباق للسلة بضغطة زر",
        "إرسال الطلب مباشرة للمطبخ"
      ],
      tag: "⚡ بدون انتظار",
      image: "https://placehold.co/600x400/2c3e50/ffffff?text=📱+QR+Code+Scanner"
    },
    {
      id: 2,
      icon: "📋",
      title: "العامل والطلبات",
      badge: "👨‍🍳 الإدارة الذكية",
      description: "لوحة تحكم متكاملة للعامل تعرض جميع الطلبات في مكان واحد مع تفاصيل دقيقة لضمان خدمة سريعة.",
      features: [
        "📍 تحديد موقع الطاولة بدقة",
        "💰 عرض ثمن كل طلب بشكل فوري",
        "📝 ملاحظات خاصة للطاهي",
        "🔄 تحديث حالة الطلب لحظة بلحظة"
      ],
      tag: "🎯 دقة 100%",
      image: "https://placehold.co/600x400/34495e/ffffff?text=👨‍🍳+Waiter+Dashboard"
    },
    {
      id: 3,
      icon: "💰",
      title: "الفاتورة الذكية",
      badge: "🧾 حساب آلي",
      description: "نظام محاسبي متطور يحسب المجموع الكلي للطلبات بدقة مع إمكانية دفع إلكتروني آمن.",
      features: [
        "🧮 حساب المجموع مع الضريبة تلقائياً",
        "📊 تفاصيل كل صنف وسعره",
        "💳 دفع إلكتروني عبر التطبيق",
        "📨 إرسال الفاتورة عبر البريد أو واتساب"
      ],
      tag: "🔒 دفع آمن",
      image: "https://placehold.co/600x400/16a085/ffffff?text=🧾+Smart+Invoice"
    }
  ];

  return (
    <>
      <Navbar transparent />
      <main>
        {/* القسم العلوي مع الخلفية والنص المتحرك */}
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen">
          <div
            className="absolute top-0 w-full h-full bg-center bg-cover"
            style={{
              backgroundImage:
                "url('https://t4.ftcdn.net/jpg/09/09/79/85/360_F_909798513_DhTQUUB8Sexbj5rBgsz5qwkarSwvQ3mA.jpg')",
            }}
          >
            {/* طبقة شفافة لتحسين وضوح النص */}
            <div className="absolute inset-0 bg-black bg-opacity-50"></div>
          </div>

          <div className="container relative mx-auto">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-8/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  {/* النص المتغيّر */}
                  <h1
                    key={texts[index]}
                    className="text-white font-semibold text-5xl md:text-6xl transition-all duration-500 mb-4"
                  >
                    {texts[index]}
                  </h1>

                  <p className="mt-4 text-lg text-blueGray-200">
                    مرحباً بك في نظام إدارة المطاعم الذكي
                  </p>
                  <p className="text-md text-blueGray-300 mt-2">
                    اكتشف كيف يغير تطبيقنا طريقة عمل المطاعم
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* قسم البطاقات - التصميم الجديد */}
        <div className="py-20 bg-gray-50">
          <div className="container mx-auto px-4">
            {/* عنوان القسم */}
            <div className="text-center mb-16">
              <h2 className="text-3xl md:text-4xl font-bold text-gray-800 mb-4">
                ✨ مهام التطبيق الأساسية ✨
              </h2>
              <p className="text-gray-600 text-lg max-w-2xl mx-auto">
                ثلاث مهام رئيسية تجعل تجربة إدارة المطعم أكثر سهولة وكفاءة
              </p>
            </div>

            {/* شبكة البطاقات */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {cardsData.map((card) => (
                <div
                  key={card.id}
                  className="bg-white rounded-2xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 hover:-translate-y-2 cursor-pointer group"
                >
                  {/* صورة البطاقة */}
                  <div className="relative h-56 overflow-hidden">
                    <img
                      src={card.image}
                      alt={card.title}
                      className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                    />
                    <div className="absolute top-4 left-4 bg-white bg-opacity-95 backdrop-blur-sm px-3 py-1 rounded-full text-sm font-semibold text-gray-700 shadow-md">
                      {card.badge}
                    </div>
                  </div>

                  {/* محتوى البطاقة */}
                  <div className="p-6">
                    <h3 className="text-2xl font-bold text-gray-800 mb-3 flex items-center gap-2">
                      <span className="text-3xl">{card.icon}</span>
                      {card.title}
                    </h3>
                    <p className="text-gray-600 leading-relaxed mb-4">
                      {card.description}
                    </p>

                    {/* قائمة الميزات */}
                    <ul className="space-y-2 mb-6">
                      {card.features.map((feature, idx) => (
                        <li key={idx} className="flex items-center gap-2 text-sm text-gray-700">
                          <span className="text-green-500 font-bold">✓</span>
                          {feature}
                        </li>
                      ))}
                    </ul>

                    {/* الجزء السفلي */}
                    <div className="pt-4 border-t border-gray-100 flex justify-between items-center">
